_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  // sample previous uFrame
ret = texture( sampler_main, vUv ).xyz;
float blur =sin(audioLow*90)*vRadius;
ret=0.125*(
GetPixel(vec2(vUv.x-0.01*blur,vUv.y-0.01*blur)) +
GetPixel(vec2(vUv.x+0.01*blur,vUv.y+0.01*blur)) +
GetPixel(vec2(vUv.x-0.01*blur,vUv.y+0.01*blur)) +
GetPixel(vec2(vUv.x+0.01*blur,vUv.y-0.01*blur)) +
GetPixel(vec2(vUv.x,vUv.y-0.01*blur)) +
GetPixel(vec2(vUv.x,vUv.y+0.01*blur)) +
GetPixel(vec2(vUv.x-0.01*blur,vUv.y)) +
GetPixel(vec2(vUv.x+0.01*blur,vUv.y)));
//add a 'audioLow overbright' effect:
ret-=-(lum(ret)<sin(uTime*90))*ret*blur+(lum(ret)>sin(-uTime*90))*ret*blur;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

static vec2 center = vec2(.5,.2+rand_preset.x*0.4);
vec2 uv1 = (vUv-center );

ret1 = 0;
int anz = 3;
int n = 0;
dz=0;
while (n < anz) {
  float dist = 1-fract(1.0/anz*n); //evtl sqrt !;
  float inten =  clamp01(1-dist);
  uv3 = .5*anz*uv1*dist + center;
  float mask = (uv3.x>0) && (uv3.x<1) &&  (uv3.y>0) && (uv3.y<1);
  mask = max(0.5,mask);
  dz.x += inten*(lum(GP(uv3+hor))- lum(GP (uv3-hor)));
  dz.y += inten*(lum(GP(uv3+ver))- lum(GP (uv3-ver)));
  dz *= length(dz)>length(uTexSize.zw)*8;
  neu = max(GP(uv3+dz*0.1*inten),GetBlur3(uv3)*.50*rand_preset.y);
  ret1 = max(ret1,neu*inten*mask);
n++;
}

uv1= multiply(uv1,rot45);
dz = multiply(dz ,rot45);
vec2 uv6 = sin(10*uv1+dz*12 + uTime*.2);
vec3 mus = .06/length(uv6) * (1+length(dz)*length(uTexSize.xy)*0.012*(0.25+2*GetBlur1(fract(1-2*vUv))));

ret = sqrt(ret1)*(.1+rand_preset.z*0.4+8*mus*clamp01(1-vRadius));
ret = 1-exp(-ret*1.3);
//ret = GetPixel(uv0);
//MilkDrop3 Solarize Mode:
ret = ret*(1-ret)*4;

  fragColor = ret;
}
